using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// --- Setup ---
var rng = new Random(42);
var sampleWords = new[] {
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "benchmark", "performance", "analysis", "optimization", "throughput",
    "extraordinary", "implementation", "characterization", "internationalization",
    "a", "I", "is", "at", "on", "of", "it", "do"
};
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
    words[i] = sampleWords[rng.Next(sampleWords.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', words));

string runtime = RuntimeInformation.FrameworkDescription;
Console.WriteLine($"Runtime: {runtime}");
Console.WriteLine();

const int warmupIterations = 500;
const int measuredIterations = 5000;

// --- Benchmarks ---
Bench("AverageWordLength", () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Bench("UniqueWordCount", () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void Bench<T>(string name, Func<T> action)
{
    // Warmup
    for (int i = 0; i < warmupIterations; i++)
        action();

    // Measured
    var timings = new double[measuredIterations];
    var sw = new Stopwatch();
    for (int i = 0; i < measuredIterations; i++)
    {
        sw.Restart();
        action();
        sw.Stop();
        timings[i] = sw.Elapsed.TotalNanoseconds;
    }

    Array.Sort(timings);
    double mean = timings.Average();
    double median = timings[timings.Length / 2];
    double p95 = timings[(int)(timings.Length * 0.95)];
    double stddev = Math.Sqrt(timings.Select(t => (t - mean) * (t - mean)).Average());

    Console.WriteLine($"{name,-25} mean={mean,10:F1} ns | median={median,10:F1} ns | p95={p95,10:F1} ns | stddev={stddev,8:F1} ns");
}

